export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
export type Step = { op: "quote"; items: Item[] };
export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
export type ScenarioResult = { results: Array<{ premium: number }> };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const itemPremium = (item: Item): number => {
  const base = ITEM_BASE_PREMIUM[item.type];
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  return base + firstInsuranceSurcharge;
};

const quotePremium = (items: Item[]): number => {
  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
  return itemsTotal + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

