export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
export type Step = { op: "quote"; items: Item[] };
export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
export type ScenarioResult = { results: Array<{ premium: number }> };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const COMPONENT_UNIT_BASE = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

// A billing group is one main item or one bundle of alike components.
// `cursed` only applies to main items.
type BillingGroup = { base: number; cursed: boolean };

const componentBundleBase = (count: number): number => {
  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
  return count * COMPONENT_UNIT_BASE;
};

const billingGroups = (items: Item[]): BillingGroup[] => {
  const groups: BillingGroup[] = [];
  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      groups.push({ base: MAIN_ITEM_BASE_PREMIUM[item.type], cursed: item.cursed === true });
    }
  }
  for (const count of componentCounts.values()) {
    groups.push({ base: componentBundleBase(count), cursed: false });
  }
  return groups;
};

const groupPremium = ({ base, cursed }: BillingGroup): number => {
  const curseSurcharge = cursed ? base * CURSE_SURCHARGE_RATE : 0;
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  return base + curseSurcharge + firstInsuranceSurcharge;
};

const quotePremium = (items: Item[]): number => {
  const itemsTotal = billingGroups(items).reduce((sum, g) => sum + groupPremium(g), 0);
  return Math.ceil(itemsTotal + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

