    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("two runes + one moonstone yield premium 88 G (75 base + 7.5 first-insurance + 5 fee = 87.5 → 88)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("three runes + three moonstones yield premium 137 G (120 base + 12 first-insurance + 5 fee = two separate blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-level modifiers
  it("a cursed sword (newcomer) yields premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("a sword with enchantment 5 (newcomer) yields premium 145 G (100 + 30 enchantment + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("a sword with enchantment 4 (newcomer) has no high-enchantment surcharge: 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });

  // Policy-level modifiers
  it("long-standing customer (2 years), single sword, first contract: 95 G (100 - 20 loyalty + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it.todo("the customer's second contract gets a 15% follow-up discount");
  it.todo("first insurance adds a 10% surcharge per item in the policy");

  // Multi-item policies and modifier scope
  it.todo("a cursed sword + plain amulet → 215 G (160 base + 50 curse + first-insurance + fee)");

  // Rounding in MHPCO favor for premiums
  it.todo("a premium calculation that yields 197.5 G rounds up to 198 G");

  // Claim — deductible, cap, special clauses
  it.todo("a regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G");
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full minus deductible)");
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, ench 8, damage 1000 G → payout 400 G");

  // Multiple damages in one claim
  it.todo("a dragon attack on insured sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
  it.todo("two swords insured; both damaged in one event → each gets its own deductible");

  // Cap
  it.todo("cap is twice the insurance sum; cap depletes across successive claims");
  it.todo("cap is based on unmodified insurance value, not modified premium");

  // Rounding for payouts
  it.todo("a payout of 350.5 G rounds down to 350 G");

  // Errors
  it.todo("quote with unknown item type → error result with non-zero exit");
  it.todo("claim referencing an item not in the policy → error result");
  it.todo("claim with negative damage amount → error result");
  it.todo("claim with more damages of a type than the policy covers → error result");
});

